external_knowledge:
Top-performing: Models with the highest average accuracy;
Popularity: Indicated by the frequency of usage or access count;
Frequency of usage: Number of times a model has been accessed.

sql:
SELECT version_number
  FROM model_versions
  WHERE model_id = 1;

SELECT AVG(evaluation_score) AS average_prediction_score
FROM predictions
WHERE dataset_type = 'train' AND evaluation_metric = 'accuracy';
